// Simula chegada irregular de pedidos: n8n não tem um
// "intervalo aleatório" nativo sem um loop de Wait, então a
// aleatoriedade fica aqui — só ~40% das execuções do cron
// realmente vira um pedido nas plataformas.
const CHANCE_DE_DISPARAR = 0.4;
if (Math.random() > CHANCE_DE_DISPARAR) {
  return [];
}

const UNIDADES_ATIVAS = [1, 2, 3, 4]; // Centro, Pinheiros, Moema, Santana
const PLATAFORMAS = ["ifood", "rappi", "proprio"];

const unidade_id = UNIDADES_ATIVAS[Math.floor(Math.random() * UNIDADES_ATIVAS.length)];
const plataforma = PLATAFORMAS[Math.floor(Math.random() * PLATAFORMAS.length)];

return [{ json: { unidade_id, plataforma } }];

// Este node recebe 1 item por produto disponível na unidade
// (RPC pública rpc_cardapio_disponivel, respeitando o toggle de
// pausa do Cardápio). Monta um pedido com 1 a 4 itens distintos
// e quantidades aleatórias.
const cardapio = $input.all().map((i) => i.json);
if (cardapio.length === 0) {
  return []; // nada disponível nessa unidade agora — não gera pedido
}

const { unidade_id, plataforma } = $("Sorteia disparo e unidade").first().json;

const embaralhado = [...cardapio].sort(() => Math.random() - 0.5);
const quantidadeItens = 1 + Math.floor(Math.random() * Math.min(4, embaralhado.length));
const itens = embaralhado.slice(0, quantidadeItens).map((p) => ({
  produto_id: p.produto_id,
  quantidade: 1 + Math.floor(Math.random() * 3),
}));

return [{ json: { unidade_id, plataforma, itens } }];
